async function handleGiteaWebhookRoute(c: Context) {
  const integrationId = c.req.param("integrationId");
  if (!integrationId) {
    return c.json({ error: "Missing integration id" }, 400);
  }

  const arrayBuffer = await c.req.arrayBuffer();
  const body = Buffer.from(arrayBuffer).toString("utf8");

  const signature =
    c.req.header("x-gitea-signature") || c.req.header("X-Gitea-Signature");

  const eventName =
    c.req.header("x-gitea-event") ||
    c.req.header("X-Gitea-Event") ||
    c.req.header("x-github-event");

  const result = await handleGiteaWebhookRequest(
    integrationId,
    body,
    signature,
    eventName,
  );

  if (!result.success) {
    return c.json({ error: result.error }, 400);
  }

  return c.json({ status: "success" });
}

import { Enforcer } from 'casbin'
import type { MiddlewareHandler, Context } from 'hono'

interface CasbinOptions {
  newEnforcer: Promise<Enforcer>
  authorizer: (c: Context, enforcer: Enforcer) => Promise<boolean>
}

export const casbin = (opt: CasbinOptions): MiddlewareHandler => {
  return async (c, next) => {
    const enforcer = await opt.newEnforcer
    if (!(enforcer instanceof Enforcer)) {
      return c.json({ error: 'Invalid enforcer' }, 500)
    }

    const isAllowed = await opt.authorizer(c, enforcer)
    if (!isAllowed) {
      return c.json({ error: 'Forbidden' }, 403)
    }
    await next()
  }
}

export function structuredLogger<L extends BaseLogger = BaseLogger>(
  options: StructuredLoggerOptions<L>
): MiddlewareHandler {
  const {
    createLogger,
    contextKey = 'logger',
    onRequest = defaultOnRequest,
    onResponse = defaultOnResponse,
    onError = defaultOnError,
  } = options

  return async (c, next) => {
    const logger = createLogger(c)
    c.set(contextKey as never, logger as never)

    const start = now()

    await onRequest(logger, c)

    await next()

    const elapsed = now() - start

    if (c.error) {
      await onError(logger, c.error instanceof Error ? c.error : new Error(String(c.error)), c)
    } else {
      await onResponse(logger, c, elapsed)
    }
  }
}

async function getCollection(db: D1Database, collectionId: string) {
  const cache = getCacheService(CACHE_CONFIGS.collection!)

  return cache.getOrSet(
    cache.generateKey('collection', collectionId),
    async () => {
      const stmt = db.prepare('SELECT * FROM collections WHERE id = ? AND is_active = 1')
      const collection = await stmt.bind(collectionId).first() as any

      if (!collection) return null

      return {
        id: collection.id,
        name: collection.name,
        display_name: collection.display_name,
        description: collection.description,
        schema: collection.schema ? JSON.parse(collection.schema) : {}
      }
    }
  )
}

async function deleteColumn(id: string) {
  const existing = await db.query.columnTable.findFirst({
    where: eq(columnTable.id, id),
  });

  if (!existing) {
    throw new HTTPException(404, { message: "Column not found" });
  }

  const [taskCount] = await db
    .select({ count: sql<number>`count(*)` })
    .from(taskTable)
    .where(eq(taskTable.columnId, id));

  if (taskCount && taskCount.count > 0) {
    throw new HTTPException(409, {
      message:
        "Cannot delete column that contains tasks. Move or delete tasks first.",
    });
  }

  await db.delete(columnTable).where(eq(columnTable.id, id));

  return existing;
}

async function getTask(taskId: string) {
  const task = await db
    .select({
      id: taskTable.id,
      title: taskTable.title,
      number: taskTable.number,
      description: taskTable.description,
      status: taskTable.status,
      priority: taskTable.priority,
      startDate: taskTable.startDate,
      dueDate: taskTable.dueDate,
      position: taskTable.position,
      createdAt: taskTable.createdAt,
      userId: taskTable.userId,
      assigneeName: userTable.name,
      assigneeId: userTable.id,
      projectId: taskTable.projectId,
    })
    .from(taskTable)
    .leftJoin(userTable, eq(taskTable.userId, userTable.id))
    .where(eq(taskTable.id, taskId))
    .limit(1);

  if (!task.length || !task[0]) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  return task[0];
}

async function getComments(taskId: string) {
  const comments = await db
    .select({
      id: commentTable.id,
      taskId: commentTable.taskId,
      userId: commentTable.userId,
      content: commentTable.content,
      createdAt: commentTable.createdAt,
      updatedAt: commentTable.updatedAt,
      userName: userTable.name,
      userImage: userTable.image,
    })
    .from(commentTable)
    .leftJoin(userTable, eq(commentTable.userId, userTable.id))
    .where(eq(commentTable.taskId, taskId))
    .orderBy(asc(commentTable.createdAt));

  return comments.map((c) => ({
    id: c.id,
    taskId: c.taskId,
    userId: c.userId,
    content: c.content,
    createdAt: c.createdAt,
    updatedAt: c.updatedAt,
    user: {
      name: c.userName ?? "",
      image: c.userImage,
    },
  }));
}

async function createProject(
  workspaceId: string,
  name: string,
  icon: string,
  slug: string,
) {
  return db.transaction(async (tx) => {
    const [createdProject] = await tx
      .insert(projectTable)
      .values({
        workspaceId,
        name,
        icon,
        slug,
      })
      .returning();

    if (createdProject) {
      for (const col of DEFAULT_PROJECT_COLUMNS) {
        await tx.insert(columnTable).values({
          projectId: createdProject.id,
          name: col.name,
          slug: col.slug,
          position: col.position,
          isFinal: col.isFinal,
        });
      }
    }

    return createdProject;
  });
}

