import type { Result, Router } from '../../router'
import { checkOptionalParameter } from '../../utils/url'
import { Node } from './node'

export class TrieRouter<T> implements Router<T> {
  name: string = 'TrieRouter'
  #node: Node<T>

  constructor() {
    this.#node = new Node()
  }

  add(method: string, path: string, handler: T) {
    const results = checkOptionalParameter(path)
    if (results) {
      for (let i = 0, len = results.length; i < len; i++) {
        this.#node.insert(method, results[i], handler)
      }
      return
    }

    this.#node.insert(method, path, handler)
  }

  match(method: string, path: string): Result<T> {
    return this.#node.search(method, path)
  }
}

function normalizePublicContentFilter(filter: QueryFilter, userRole?: string): QueryFilter {
  if (canReadNonPublicContent(userRole)) {
    return filter
  }

  const normalizedFilter: QueryFilter = {
    ...filter,
    where: stripStatusConditions(filter.where)
  }

  if (!normalizedFilter.where) {
    normalizedFilter.where = { and: [] }
  }

  if (!normalizedFilter.where.and) {
    normalizedFilter.where.and = []
  }

  normalizedFilter.where.and.push({
    field: 'status',
    operator: 'equals',
    value: 'published'
  })

  return normalizedFilter
}

async function reorderColumns(
  projectId: string,
  columns: Array<{ id: string; position: number }>,
) {
  for (const col of columns) {
    const [updated] = await db
      .update(columnTable)
      .set({ position: col.position })
      .where(
        and(eq(columnTable.id, col.id), eq(columnTable.projectId, projectId)),
      )
      .returning({ id: columnTable.id });

    if (!updated) {
      throw new HTTPException(400, {
        message: `Column ${col.id} does not belong to this project`,
      });
    }
  }

  const updated = await db.query.columnTable.findMany({
    where: eq(columnTable.projectId, projectId),
    orderBy: (columns, { asc }) => [asc(columns.position)],
  });

  return updated;
}

async function archiveProject(id: string, workspaceId: string) {
  const [existingProject] = await db
    .select()
    .from(projectTable)
    .where(
      and(eq(projectTable.id, id), eq(projectTable.workspaceId, workspaceId)),
    );

  if (!existingProject) {
    throw new HTTPException(404, {
      message:
        "Project doesn't exist or doesn't belong to the specified workspace",
    });
  }

  const [archivedProject] = await db
    .update(projectTable)
    .set({ archivedAt: new Date() })
    .where(eq(projectTable.id, id))
    .returning();

  if (!archivedProject) {
    throw new HTTPException(500, {
      message: "Failed to archive project",
    });
  }

  return archivedProject;
}

async function unarchiveProject(id: string, workspaceId: string) {
  const [existingProject] = await db
    .select()
    .from(projectTable)
    .where(
      and(eq(projectTable.id, id), eq(projectTable.workspaceId, workspaceId)),
    );

  if (!existingProject) {
    throw new HTTPException(404, {
      message:
        "Project doesn't exist or doesn't belong to the specified workspace",
    });
  }

  const [unarchivedProject] = await db
    .update(projectTable)
    .set({ archivedAt: null })
    .where(eq(projectTable.id, id))
    .returning();

  if (!unarchivedProject) {
    throw new HTTPException(500, {
      message: "Failed to unarchive project",
    });
  }

  return unarchivedProject;
}

