export class MedleyRouter<T> implements Router<T> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  router: any
  name: string = 'MedleyRouter'

  constructor() {
    this.router = new OriginalRouter()
  }

  add(method: string, path: string, handler: T): void {
    const store = this.router.register(path)
    store[method] = handler
  }

  match(method: string, path: string): Result<T> {
    const route = this.router.find(path)

    if (route) {
      return [[[route['store'][method]], route['params']]]
    }

    return [[], []]
  }
}

function getErrorHandler(dir: string, map: Record<string, Record<string, ErrorFile>>) {
  for (const [mapDir, content] of Object.entries(map)) {
    if (dir === mapDir) {
      const errorFile = content[ERROR_FILENAME]
      if (errorFile) {
        const matchedErrorHandler = errorFile.default
        if (matchedErrorHandler) {
          const errorHandler: ErrorHandler = async (error, c) => {
            const importingIslands = errorFile[IMPORTING_ISLANDS_ID]
            if (importingIslands) {
              c.set(IMPORTING_ISLANDS_ID, importingIslands)
            }
            c.status(500)
            return matchedErrorHandler(error, c)
          }
          return errorHandler
        }
      }
    }
  }
}

const normalizeConfig = (
  config?: HttpInstrumentationConfig
): NormalizedHttpInstrumentationConfig => {
  const reqHeadersSrc = [...(config?.captureRequestHeaders ?? [])]
  const resHeadersSrc = [...(config?.captureResponseHeaders ?? [])]
  const requestHeaderSet = new Set(reqHeadersSrc.map((h) => h.toLowerCase()))
  const responseHeaderSet = new Set(resHeadersSrc.map((h) => h.toLowerCase()))
  const norm: NormalizedHttpInstrumentationConfig = {
    ...config,
    requestHeaderSet,
    responseHeaderSet,
    captureActiveRequests: config?.captureActiveRequests ?? true,
    captureRequestHeaders: reqHeadersSrc,
    captureResponseHeaders: resHeadersSrc,
  }
  return norm
}

export async function jweEncrypt(
  payload: CookiePayload,
  key: EncryptionKey,
  duration?: MaxAgeDuration
): Promise<{ jwe: string; maxAge?: number }> {
  const now = epoch()
  const iat = payload.iat ?? now
  const jwt = new jose.EncryptJWT(payload)
    .setIssuedAt(iat)
    .setProtectedHeader({ enc: ENC, alg: ALG })

  let maxAge

  if (duration) {
    const exp = calculateExpiration(iat, now, duration)
    maxAge = Math.max(0, exp - now)
    jwt.setExpirationTime(exp)
  }

  const jwe = await jwt.encrypt(key)

  return { jwe, maxAge }
}

const validateDirectReadMethod = (method: string): TypeError | undefined => {
  if (!methodTokenRegExp.test(method)) {
    return new TypeError(`'${method}' is not a valid HTTP method.`)
  }
  // Keep TRACE workaround behavior, but preserve native rejection for other
  // forbidden methods when using the direct-read fast path.
  // Only exact upper-case TRACE is treated as the existing workaround target.
  const normalized = method.toUpperCase()
  if (
    normalized === 'CONNECT' ||
    normalized === 'TRACK' ||
    (normalized === 'TRACE' && method !== 'TRACE')
  ) {
    return new TypeError(`'${method}' HTTP method is unsupported.`)
  }
  return undefined
}

Object.defineProperty(Response, 'json', {
  value: function json(data?: unknown, init?: ResponseInit): Response {
    const body = JSON.stringify(data)
    if (body === undefined) {
      throw new TypeError('The data is not JSON serializable')
    }
    const initHeaders = init?.headers
    let headers: Record<string, string> | Headers
    if (initHeaders) {
      headers = new Headers(initHeaders)
      if (!headers.has('content-type')) {
        headers.set('content-type', 'application/json')
      }
    } else {
      headers = { 'content-type': 'application/json' }
    }
    return new Response(body, {
      status: init?.status ?? 200,
      statusText: init?.statusText,
      headers,
    })
  },
  writable: true,
  configurable: true,
})

export const createBasePathRewriter = (
  base: string | undefined
): ((request: Request) => Request) | undefined => {
  const normalizedBase = normalizeBasePath(base)
  if (!normalizedBase) {
    return undefined
  }
  const prefixLength = normalizedBase.length
  const prefixWithSlash = `${normalizedBase}/`
  return (request) => {
    const url = new URL(request.url)
    const { pathname } = url
    if (pathname === normalizedBase) {
      url.pathname = '/'
    } else if (pathname.startsWith(prefixWithSlash)) {
      url.pathname = pathname.slice(prefixLength) || '/'
    } else {
      return request
    }
    return new Request(url, request)
  }
}

async fetchWithCoalescing(
  key: string,
  fetcher: () => Promise<Record<string, unknown> | null>,
): Promise<Record<string, unknown> | null> {
  // Check cache first
  const cached = this.get(key);
  if (cached !== undefined && cached !== null) {
    return cached;
  }

  // Track if this was coalesced
  const wasInFlight = isInFlight(key);

  const data = await coalesce(key, fetcher);

  if (wasInFlight) {
    entityCacheMetrics.recordCoalesced();
  }

  // Cache the result if fetched successfully
  if (data) {
    this.set(key, data);
  }

  return data;
}

function tryFastConsume(key: string, cost: number, budget: number): 'allow' | 'check-db' {
  const now = Date.now();
  const entry = cache.get(key);

  if (!entry || now - entry.windowStart >= WINDOW_MS) {
    // New window — start fresh
    cache.set(key, { consumed: cost, windowStart: now });
    return 'allow';
  }

  const projectedTotal = entry.consumed + cost;

  if (projectedTotal < budget * FAST_PATH_THRESHOLD) {
    entry.consumed = projectedTotal;
    cache.set(key, entry);
    return 'allow';
  }

  // Near or over budget — let the DB path handle it for accuracy
  return 'check-db';
}

function resolveSchemaFieldType(fieldConfig: Record<string, any>): string {
  if (fieldConfig.type === 'slug' || fieldConfig.format === 'slug') {
    return 'slug'
  }

  if (fieldConfig.type && fieldConfig.type !== 'string') {
    return fieldConfig.type
  }

  if (fieldConfig.format === 'richtext') {
    return 'richtext'
  }

  if (fieldConfig.format === 'media') {
    return 'media'
  }

  if (fieldConfig.format === 'date-time') {
    return 'date'
  }

  if (Array.isArray(fieldConfig.enum)) {
    return 'select'
  }

  return fieldConfig.type || 'string'
}

function toResponse(integration: {
  id: string;
  projectId: string;
  config: string;
  isActive: boolean | null;
  createdAt: Date;
  updatedAt: Date;
}) {
  const config = normalizeDiscordConfig(
    JSON.parse(integration.config) as DiscordConfig,
  );

  return {
    id: integration.id,
    projectId: integration.projectId,
    channelName: config.channelName ?? null,
    webhookConfigured: Boolean(config.webhookUrl),
    maskedWebhookUrl: config.webhookUrl
      ? maskWebhookUrl(config.webhookUrl)
      : "",
    events: {
      ...defaultDiscordEvents,
      ...(config.events ?? {}),
    },
    isActive: integration.isActive,
    createdAt: integration.createdAt,
    updatedAt: integration.updatedAt,
  };
}
